// Scoped CSS injected with the SVG. This is what actually colors and animates
// the lines — done in CSS (not JS) so it works even with zero JavaScript.
// `currentColor` picks up the wrapper's `color`; pathLength normalization (see
// MARKUP) lets the dash animation run without measuring geometry.
const STYLE = `<style>
.topo-lines svg { display: block; width: 100%; height: 100%; }
.topo-lines path {
  fill: none;
  stroke: currentColor;
  stroke-width: 1.25px;
  vector-effect: non-scaling-stroke;
  stroke-dasharray: 1;
  stroke-dashoffset: 1;
  animation: topoDraw 12s ease-in-out infinite;
}
@keyframes topoDraw {
  0%   { stroke-dashoffset: 1; }
  28%  { stroke-dashoffset: 0; }
  55%  { stroke-dashoffset: 0; }
  82%  { stroke-dashoffset: 1; }
  100% { stroke-dashoffset: 1; }
}
@media (prefers-reduced-motion: reduce) {
  .topo-lines path { animation: none; stroke-dashoffset: 0; }
}
</style>`;

// Normalize every path to unit length so the CSS dash animation is uniform and
// needs no getTotalLength(), then prepend the scoped styles.
const MARKUP = STYLE + RAW_SVG.replace(/<path /g, '<path pathLength="1" ');

export interface TopoLinesProps {
  /** Stroke color for the lines. Defaults to white (light lines). */
  color?: string;
  /** Overall opacity of the layer. Keep low for a subtle texture. */
  opacity?: number;
  className?: string;
}

export function TopoLines({
  color = "#ffffff",
  opacity = 0.64,
  className = "",
}: TopoLinesProps) {
  const ref = useRef<HTMLDivElement>(null);

  // Enhancement only: give each line a random duration + start phase so they
  // animate independently. The CSS above already animates them without this,
  // so a failure here just means the lines animate in sync — never black.
  useEffect(() => {
    const root = ref.current;
    if (!root) return;
    root.querySelectorAll<SVGPathElement>("path").forEach((path) => {
      const dur = 9 + Math.random() * 9; // 9–18s full cycle
      path.style.animationDuration = `${dur}s`;
      path.style.animationDelay = `${-Math.random() * dur}s`;
    });
  }, []);

  return (
    <div
      ref={ref}
      aria-hidden="true"
      className={`topo-lines pointer-events-none absolute inset-0 -z-10 overflow-hidden ${className}`}
      style={{ color, opacity }}
      dangerouslySetInnerHTML={{ __html: MARKUP }}
    />
  );
}
